(2, 'NIT-007', 'Nẹp Lập Là Inox 100mm – LA100', 'Nẹp lập là inox 100mm với kích thước mặt cắt là 100mm x 0.3mm chuyên dùng trong thi công công trình thương mại, showroom, mặt dựng lớn. Chất liệu Inox 201 chống ăn mòn cao, bền bỉ theo thời gian. Màu sắc: Trắng gương, vàng gương, đen dương, vàng hồng.', 'https://svietdecor.com/wp-content/uploads/2025/06/La-cuon-inox-LA100-1.webp', 'm', 59000, 50, TRUE),
(2, 'NIT-008', 'Nẹp Lập Là Inox 80mm – LA80', 'Nẹp lập là inox 80mm với kích thước mặt cắt 80mm x 0.3mm; cuộn dài 50m. Dùng cho công trình cần che phủ mảng lớn như mặt dựng, bảng hiệu hoặc khu vực ốp lát nội thất kích thước lớn. Chất liệu Inox 201 đảm bảo độ sáng bóng và bền màu theo thời gian.', 'https://svietdecor.com/wp-content/uploads/2025/06/La-cuon-inox-LA80-1.webp', 'm', 49000, 50, TRUE),
(2, 'NIT-009', 'Nẹp Lập Là Inox 50mm – LA50', 'Nẹp lập là inox 50mm có chiều dài mặt cắt 50mm, độ dày 0.3mm; cuộn dài 50m. Màu sắc: Trắng gương, vàng gương, đen dương, vàng hồng. Nẹp dùng tạo điểm nhấn cho các mảng tường, che mép gạch/ đá/ gỗ giúp tăng thẩm mỹ cho công trình.', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-Lap-La-Inox-50mm-1.webp', 'm', 28000, 50, TRUE),
(2, 'NIT-010', 'Nẹp Lập Là Inox 40mm – LA40', 'Nẹp lập là inox 40mm làm từ chất liệu Inox 201. Kích thước mặt cắt 40mm X 0.3mm, cuộn dài 50m. Màu sắc: Trắng gương, vàng gương, đen dương, vàng hồng. Nẹp dùng để trang trí nội thất, vách tường, sàn nhà, cửa,... giúp tăng tính thẩm mỹ cho công trình.', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-Lap-La-Inox-40mm-2.webp', 'm', 25000, 50, TRUE),
(2, 'NIT-011', 'Nẹp Lập Là Inox 30mm – LA30', 'Nẹp lập là inox 30mm với kích thước mặt cắt 30mm x 0.3mm, cuộn dài 5m. Màu sắc: Trắng gương, vàng gương, đen dương, vàng hồng. Nẹp được dùng để tạo các đường nét vàng gương trang trí cho các công trình giúp tăng tính thẩm mỹ và độ hoàn thiện.', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-Lap-La-Inox-30mm-3.webp', 'm', 44000, 50, TRUE),
(2, 'NIT-012', 'Nẹp Lập Là Inox 20mm – LA20', 'Nẹp lập là inox 20 có kích thước mặt cắt rộng là 20mm, dày 0.3mm; cuộn dài 5m. Nẹp được dùng trong các vị trí như viền tường, cạnh cánh tủ hoặc viền nẹp nội thất. Chất liệu inox 201, sản phẩm có độ bền cao, không gỉ sét.', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-Lap-La-Inox-20mm-3.webp', 'm', 32000, 50, TRUE),
(2, 'NIT-013', 'Nẹp Lập Là Inox 10mm – LA10', 'Nẹp lập là inox 10mm với màu sắc: Trắng gương, vàng gương, đen dương, vàng hồng Kích thước mặt cắt: 10mm x 0.3mm; cuộn dài 5m.', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-Lap-La-Inox-10mm-3.webp', 'm', 28000, 50, TRUE),
(2, 'NIT-014', 'Nẹp Inox Chữ L5x25 mm', '', 'https://svietdecor.com/wp-content/uploads/2024/07/nep-inox-chu-L5x25mm-2.webp', 'm', 65000, 50, TRUE),
(2, 'NIT-015', 'Nẹp Inox 304 V35 mm', '', 'https://svietdecor.com/wp-content/uploads/2024/07/Nep-inox-304-V35-3.webp', 'm', 96000, 50, TRUE),
(2, 'NIT-016', 'Nẹp Inox 304 T10 mm', '', 'https://svietdecor.com/wp-content/uploads/2024/07/Nep-Inox-T10-3.webp', 'm', 80000, 50, TRUE),
(2, 'NIT-017', 'Nẹp Len Chân Tường Inox Kiểu Vuông', '', 'https://svietdecor.com/wp-content/uploads/2024/06/Len-chan-tuong-inox-vuong-2.7.25-8.webp', 'm', 200000, 50, TRUE),
(2, 'NIT-018', 'Nẹp Thảm Inox, Nẹp chặn thảm inox', 'Nẹp thảm inox là một phụ kiện được sử dụng để bảo vệ và trang trí các cạnh thảm, giúp tăng tính thẩm mỹ và độ bền cho thảm.', 'https://svietdecor.com/wp-content/uploads/2023/10/nep-tham-inox.jpg', 'm', 80000, 50, TRUE),
(2, 'NIT-019', 'Nẹp Inox Sàn Gỗ', 'Nẹp inox sàn gỗ là phụ kiện được sử dụng để che chắn và bảo vệ các đường viền của sàn gỗ, giúp tăng tính thẩm mỹ và độ bền cho sàn.', 'https://svietdecor.com/wp-content/uploads/2023/09/nep-inox-san-go.jpg', 'm', 80000, 50, TRUE),
(2, 'NIT-020', 'Nẹp Inox Kính Cường Lực', '', 'https://svietdecor.com/wp-content/uploads/2023/08/nep-inox-kinh-cuong-luc.jpg', 'm', 80000, 50, TRUE),
(2, 'NIT-021', 'Nẹp INOX Bán Nguyệt (Nẹp điện inox)', '', 'https://svietdecor.com/wp-content/uploads/2023/08/INOX-BAN-NGUYET-5.webp', 'm', 0, 50, TRUE),
