(2, 'NIT-051', 'Nẹp Inox La Cuộn Đủ Kích Thước', 'Các loại nẹp la inox cuộn độ rộng mặt cắt gồm: 10mm, 20mm, 30mm, 40mm, 50mm, 80mm, 100mm,... Nẹp la cuộn có độ dày thường là 0.3mm; chiều dài cuộn từ 5m - 50m hoặc theo đơn đặt hàng sản xuất. Có hai loại la cuộn gồm loại có băng keo dán sẵn phía mặt sau nẹp (loại mặt cắt 10mm, 20mm, 30mm) và loại không có phải dùng keo chuyên dụng để dán thi công. Nẹp có đủ các màu sắc: Trắng gương, vàng gương, đen dương, vàng hồng.', 'https://svietdecor.com/wp-content/uploads/2021/12/Nep-inox-la-cuon.webp', 'm', 28000, 50, TRUE),
(2, 'NIT-052', 'La Inox 304 5mm – Tạo chỉ', 'Nẹp la inox 304 5mm dùng để tạo chỉ trang trí trên các bề mặt sàn, tường,... Nẹp có đủ các kích thước chiều dài mặt cắt và độ dày từ 5mm, chiều dài theo đặt hàng sản xuất.', 'https://svietdecor.com/wp-content/uploads/2021/12/1x1-trang-15-scaled.webp', 'm', 0, 50, TRUE),
(3, 'NNH-001', 'Nẹp nhựa JW – U1210 – Nẹp bọc viền, chỉ âm thạch cao', '', 'https://svietdecor.com/wp-content/uploads/2026/02/Nep-nhua-JW-U1210-1.webp', 'm', 21000, 50, TRUE),
(3, 'NNH-002', 'Nẹp nhựa JW – U105 – Nẹp bọc viền, chỉ âm thạch cao', '', 'https://svietdecor.com/wp-content/uploads/2026/02/Nep-nhua-JW-U105-a1.webp', 'm', 21000, 50, TRUE),
(3, 'NNH-003', 'Nẹp nhựa JW – UT (JTC5.0) – Nẹp U ron thạch cao', '', 'https://svietdecor.com/wp-content/uploads/2026/02/Nep-nhua-JW-UT-1.webp', 'm', 25000, 50, TRUE),
(3, 'NNH-004', 'Nẹp nhựa JW – M203020 – Nẹp trần thạch cao giật cấp', '', 'https://svietdecor.com/wp-content/uploads/2026/02/Nep-nhua-JW-M203020-1.webp', 'm', 28000, 50, TRUE),
(3, 'NNH-005', 'Nẹp nhựa JW – M201010 – Nẹp trần thạch cao giật cấp', '', 'https://svietdecor.com/wp-content/uploads/2026/02/Nep-nhua-JW-M201010-1b.webp', 'm', 25000, 50, TRUE),
(3, 'NNH-006', 'Nẹp nhựa JW-D001 | Nẹp góc vòm, góc tường cong', '', 'https://svietdecor.com/wp-content/uploads/2026/02/Nep-nhua-JW-D001-1a.webp', 'm', 22000, 50, TRUE),
(3, 'NNH-007', 'Nẹp góc thạch cao V10x20', '', 'https://svietdecor.com/wp-content/uploads/2026/01/Nep-Goc-Thach-Cao-V10x20-161262.webp', 'm', 6000, 50, TRUE),
(3, 'NNH-008', 'Nẹp chỉ ngắt nước dưới NAN DC', 'Nẹp chỉ ngắt nước dưới NAN DC với chất liệu nhựa PVC nguyên sinh; Kích thước mặt cắt 47mm x 21mm, chiều dài 2.5m. Được dùng trong hạng mục tạo chỉ ngắt nước dưới.', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-chi-ngat-nuoc-NAN-DC-4.webp', 'm', 20000, 50, TRUE),
(3, 'NNH-009', 'Nẹp khe co giãn sàn bê tông', 'Nẹp khe co giãn sàn bê tông là sản phẩm nẹp trang trí được làm từ chất liệu nhựa PVC nguyên sinh, kích thước mặt cắt với chiều dài đáy 30mm x 8mm, sản phẩm dùng để tạo khe co giãn cho các sân, đường bê tông có diện tích lớn.', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-khe-co-gian-san-be-tong-4.webp', 'm', 36000, 50, TRUE),
(3, 'NNH-010', 'Nẹp vát góc bê tông T30', 'Nẹp vát góc bê tông T30 có độ dài thanh là 2.5 mét, mặt cắt với chiều dài đáy là 28mm và 2 cạnh bên là 20mm.', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-vat-goc-be-tong-T30-3.webp', 'm', 22000, 50, TRUE),
(3, 'NNH-011', 'Nẹp vát góc bê tông T20', 'Nẹp vát góc bê tông T20 có độ dài thanh là 2.5 mét, mặt cắt với chiều dài đáy là 20mm và 2 cạnh bên là 14mm. Nẹp vát góc bê tông còn được gọi là Chamfer (nẹp tam giác).', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-vat-goc-be-tong-T20-3.webp', 'm', 16000, 50, TRUE),
(3, 'NNH-012', 'Nẹp nhựa bo góc ngoài YS10', 'SViệt Decor cung cấp nẹp nhựa ốp lát chính hãng, nẹp được làm bằng chất liệu nhựa PVC nguyên sinh bền chắc giúp bảo vệ góc ốp lát không bị sứt mẻ khi có va chạm.', 'https://svietdecor.com/wp-content/uploads/2025/06/Nep-bo-goc-ngoai-YS10-3.webp', 'm', 16000, 50, TRUE),
(3, 'NNH-013', 'Nẹp Ron Âm Trần Thạch Cao U12', '', 'https://svietdecor.com/wp-content/uploads/2024/09/14-Nep-Ron-Am-Tran-Thach-Cao-U12-a-1.webp', 'm', 20730, 50, TRUE),
